import{_ as i,c as t,o as r,ak as o}from"./chunks/framework.CYxz2ou1.js";const d=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"NanoLife/A-书架/1-读书笔记/202207-明朝那些事.md","filePath":"NanoLife/A-书架/1-读书笔记/202207-明朝那些事.md","lastUpdated":1775467143000}'),n={name:"NanoLife/A-书架/1-读书笔记/202207-明朝那些事.md"};function a(s,l,e,p,u,g){return r(),t("div",null,[...l[0]||(l[0]=[o('<h2 id="📘-基本信息" tabindex="-1">📘 基本信息 <a class="header-anchor" href="#📘-基本信息" aria-label="Permalink to &quot;📘 基本信息&quot;">​</a></h2><ul><li>📘 <strong>书名：明朝那些事</strong></li><li>🕵️‍♂️ <strong>作者</strong>：当年明月</li><li>🥂 <strong>推荐分数</strong>：9.5</li><li>⏰ <strong>阅读时间</strong>：2022 年 7 月</li></ul><p>![[Pasted image 20260405110327.png|179]]</p><h2 id="📝-总结" tabindex="-1">📝 总结 <a class="header-anchor" href="#📝-总结" aria-label="Permalink to &quot;📝 总结&quot;">​</a></h2><p>要是每个朝代都有这样的作品就好了。</p><h2 id="📖-摘录" tabindex="-1">📖 摘录 <a class="header-anchor" href="#📖-摘录" aria-label="Permalink to &quot;📖 摘录&quot;">​</a></h2><p><strong>朱元璋-洪武</strong></p><ul><li>元朝末年，官逼民反，朱元璋造反，当了皇帝。</li><li>与陈友谅大战。</li><li>为了保护子孙皇位，朱元璋杀了很多开国功臣。</li></ul><p><strong>朱允炆-建文</strong></p><ul><li>担心藩王造反，开始削藩。燕王朱棣不得不反。</li><li>一直选用李景隆对抗朱棣，奈何李景隆是个庸才，耽误战机。</li><li>朱棣攻入京城后烧掉皇宫失踪。</li></ul><p><strong>朱棣-永乐</strong></p><ul><li>朱元璋第四个儿子。</li><li>朱棣军师姚广孝。以靖难的名义造反。</li><li>命令谢晋修书《永乐大典》，谢晋号称永乐第一大才子。</li><li>迁都北京。原因：自己是燕王一直住北京+住北方压制蒙古部落。</li><li>设立内阁，东厂，巡抚三大机构。</li><li>继承人之争：朱高炽与朱高煦为了争夺太子之位而进行了权益斗争。</li><li>当政时内阁的重要人物-“三杨”：杨士奇，杨荣，杨溥。</li><li>评价：是个好皇帝，但不是个好人。</li></ul><p><strong>朱高炽</strong></p><ul><li>仁厚。敢于废除朱棣的不合理政令。</li><li>在位仅十个月就病逝。</li></ul><p><strong>朱瞻基</strong></p><ul><li>在位十年。与朱高炽统治加起来开创盛世，世称仁宣之治。</li><li>刚登基朱高炽造反。朱瞻基御驾亲征平反。朱高炽落败。做事不做绝，彻头彻尾的丑角。</li><li>好皇帝。没啥不良嗜好。只是喜欢斗蛐蛐。</li><li>年仅 38 岁。为自己 5 岁的儿子选了五位顾命大臣。</li></ul><p><strong>朱祁镇-明英宗</strong></p><ul><li>算是开明的皇帝。</li><li>大太监王振崛起。</li><li>于谦崭露头角。</li><li>也先出兵攻打明朝。王振说服朱祁镇御驾亲征。但是王振过于垃圾。被也先打败，几乎全军覆没，史称土木堡之战。朱祁镇被也先俘虏。</li></ul><p><strong>朱祁钰</strong></p><ul><li>朱祁镇被抓之后，临时选出的皇帝。朱祁镇成为太上皇。</li><li>也先带兵进攻北京。于谦率众将士保卫了京城，史称 “京城保卫战”。</li><li>也先同意送回朱祁镇，但朱祁钰不想朱祁镇回国。所以派了使臣也不打算接朱祁镇回国。</li><li>后来派去的使臣杨善是接朱祁镇回国的重要功臣。杨善能言善辩，说服了也先派人将朱祁镇送回明朝。</li><li>但是朱祁钰将朱祁镇囚禁起来，共 7 年。</li><li>朱祁钰因病身故。</li></ul><p><strong>朱祁镇</strong></p><ul><li>阴谋集团 “还乡团”(徐有贞，曹吉祥，石亨等人)策划并实施 “夺门之变”，帮助朱祁镇复辟重新当上皇帝。</li><li>徐有贞为报复于谦，公报私仇，利用朱祁镇害死了于谦。</li><li>“还乡团” 内部成员互相算计，都倒台了。</li></ul><p><strong>朱见深-成化</strong></p><ul><li>在位 23 年。</li><li>由于其父朱祁镇被也先俘虏，回国后被朱祁钰囚禁，朱见深从小由比他大 17 岁的万宫女带大。</li><li>为于谦平反。</li><li>万宫女成为万贵妃。万贵妃设计除掉了所有怀孕妃子的孩子。</li><li>朱见深临幸了一个宫女，生下了朱佑樘。万贵妃命令除掉朱佑樘，但是手下却放过了朱佑樘。朱佑樘在宫里吃百家饭长大，直到五岁才与朱见深相认。</li><li>在位期间，不理朝政，但也不昏庸。评价：懦弱，对好人坏人都强硬不起来。</li><li>万贵妃是朱见深的精神支柱，万贵妃病逝后不久，朱见深也去世。</li></ul><p><strong>朱佑樘</strong></p><ul><li>为人宽厚仁慈，躬行节俭，不近女色，勤于政事，重视司法，大开言路，努力扭转朝政腐败状况，驱逐奸佞，勤于政事，励精图治，任用王恕，刘大夏等为人正直的大臣，史称 “弘治中兴”。</li><li>从小经历了很多磨难，励志当好皇帝。</li><li>内阁成员：李东阳，谢迁等。</li><li>评价：好人+好皇帝。</li></ul><p><strong>朱厚照</strong></p><ul><li>明朝最会玩的皇帝。</li><li>打太极刘瑾猖獗一时，六部九卿集体上书要求处死刘瑾。</li><li>刘瑾善于抓住朱厚照爱玩的特点，非但没有被处理反而更强势。六部九卿很多都被报复。许多官员上书骂刘瑾，其中包含王守仁。王守仁被打，并贬官到贵州陇场。</li><li>刘瑾派人路上暗杀王守仁。王守仁逃脱后见了父亲之后，决定去贵州赴任。</li><li>王守仁父亲王华，是状元出身。</li><li>王阳明一直学习程朱理学。参悟格物致知的道理。后陇场悟道，领悟知行合一的智慧。体会到 “去人欲望” 是不对的，人欲永远存在。</li><li>杨一清为太监张永出谋划策，成功打倒刘瑾。</li><li>唐寅唐伯虎是同期的大才子。科举考试中陷入 “作弊事件” 被处罚永远不允许再参与考试。</li><li>宁王朱宸濠叛乱。朱宸濠买通朝廷内部许多官员，秘密准备造反。</li><li>王守仁时任江西巡抚，决定平反。但是王守仁开始没有兵，于是通过自己的计谋，抓住朱宸濠内心的弱点，最后平反。</li><li>朱厚照以平宁王之乱为借口，借机代表下江南。途中四处游玩，所到之处民不聊生。南巡图中游玩落水后生病，后驾崩。</li></ul><p><strong>朱厚熜-嘉靖</strong></p><ul><li>朱厚照没有儿子，杨廷和安排朱厚熜当了皇帝。</li><li>朱厚熜由于是藩王当皇帝，杨廷和主张朱厚熜认朱厚照为父，但是朱厚熜不同意，主张认自己的父母。双方就此展开博弈，史称 “大礼议事件”。这实际是权利的博弈。最后杨廷和输了，退出历史舞台。</li><li>嘉靖喜欢修道。</li><li>大奸臣严嵩崛起，依靠其奸诈狡猾当上了内阁首府。</li><li>徐阶崛起，入阁。</li><li>嘉靖年间，倭寇猖獗。两大头领为汪直和徐海。胡宗宪奉命打击倭寇，徐文长(徐渭)受胡宗宪赏识，作为打击倭寇的军师。</li><li>戚继光辅佐胡宗宪抗倭。戚继光会带兵，组织了戚家军。后成功抗倭。</li><li>徐阶隐忍了十几年，最终扳倒了严嵩。严嵩的第一智囊是其子严世蕃，十分聪明狡诈。徐阶也设计打败严世蕃。徐阶后成为首辅。徐阶任用了很多优秀的人才，如张居正。</li><li>明代第一清官海瑞为人十分清廉，还敢写奏书直接骂嘉靖，后直接入狱，嘉靖死后被徐阶放出。</li><li>嘉靖后期徐阶成为实际的掌权人，权倾天下。徐阶任命张居正，高拱为裕王(后为隆庆)的老师。</li></ul>',30)])])}const c=i(n,[["render",a]]);export{d as __pageData,c as default};
